function execProcess(command, args, timeoutMs) {
  return new Promise((resolve2) => {
    const proc = spawn(command, args, {
      timeout: timeoutMs,
      cwd: SANDBOX_DIR,
      env: {
        ...process.env,
        HOME: SANDBOX_DIR,
        PATH: "/usr/bin:/bin:/usr/local/bin"
      }
    });
    let stdout = "";
    let stderr = "";
    proc.stdout?.on("data", (d) => {
      stdout += d.toString();
    });
    proc.stderr?.on("data", (d) => {
      stderr += d.toString();
    });
    proc.on("error", (e) => resolve2({ stdout, stderr, error: e.message }));
    proc.on("close", (code2) => {
      if (code2 !== 0 && !stderr) {
        resolve2({ stdout, stderr, error: `Exit code: ${code2}` });
      } else {
        resolve2({ stdout, stderr, error: code2 !== 0 ? `Exit code: ${code2}` : undefined });
      }
    });
  });
}
async function pandasCreate(data, name = "df") {
  try {
    const parsed = JSON.parse(data);
    const rows = Array.isArray(parsed) ? parsed : [parsed];
    const keys = Object.keys(rows[0] || {});
    const summary = {
      name,
      rowCount: rows.length,
      columns: keys,
      preview: rows.slice(0, 5)
    };
    return {
      success: true,
      output: JSON.stringify(summary, null, 2)
    };
  } catch (e) {
    return { success: false, output: "", error: `Invalid JSON: ${e.message}` };
  }
}
async function pandasFilter(data, conditions) {
  try {
    const parsedConditions = JSON.parse(conditions);
    const filtered = data.filter((row) => {
      for (const [key, op] of Object.entries(parsedConditions)) {
        const rowVal = row[key];
        if (typeof op === "object") {
          for (const [cmp, val] of Object.entries(op)) {
            switch (cmp) {
              case "$eq":
                if (rowVal !== val)
                  return false;
                break;
              case "$ne":
                if (rowVal === val)
                  return false;
                break;
              case "$gt":
                if (rowVal <= val)
                  return false;
                break;
              case "$gte":
                if (rowVal < val)
                  return false;
                break;
              case "$lt":
                if (rowVal >= val)
                  return false;
                break;
              case "$lte":
                if (rowVal > val)
                  return false;
                break;
              case "$contains":
                if (!String(rowVal).includes(String(val)))
                  return false;
                break;
            }
          }
        } else {
          if (rowVal !== op)
            return false;
        }
      }
      return true;
    });
    return {
      success: true,
      output: JSON.stringify(filtered, null, 2)
    };
  } catch (e) {
    return { success: false, output: "", error: e.message };
  }
}
async function pandasAggregate(data, groupBy, aggregations) {
  try {
    const rows = data;
    const groups = new Map;
    for (const row of rows) {
      const key = groupBy.map((k) => String(row[k])).join("|");
      if (!groups.has(key))
        groups.set(key, []);
      groups.get(key).push(row);
    }
    const results = [];
    for (const [key, groupRows] of groups) {
      const result = {};
      const keyParts = key.split("|");
      groupBy.forEach((k, i2) => {
        result[k] = keyParts[i2];
      });
      for (const [col, fn] of Object.entries(aggregations)) {
        const values = groupRows.map((r) => Number(r[col])).filter((v) => !isNaN(v));
        switch (fn) {
          case "sum":
            result[`${col}_sum`] = values.reduce((a, b) => a + b, 0);
            break;
          case "avg":
            result[`${col}_avg`] = values.length ? values.reduce((a, b) => a + b, 0) / values.length : 0;
            break;
          case "count":
            result[`${col}_count`] = values.length;
            break;
          case "min":
            result[`${col}_min`] = Math.min(...values);
            break;
          case "max":
            result[`${col}_max`] = Math.max(...values);
            break;
        }
      }
      results.push(result);
    }
    return { success: true, output: JSON.stringify(results, null, 2) };
  } catch (e) {
    return { success: false, output: "", error: e.message };
  }
}

